#include<bits/stdc++.h>
using namespace std;
const int MAXN = 1e5 + 10;
long long a[MAXN];
int n,m;
bool check(int x){
	int cnt = 0, sum = 0;
	for(int i = 1; i <= n; i++){
		if(sum + a[i] > x){
//			cout << a[i] << " ";
			cnt++;
			sum = 0;
		}
		if(a[i] > x)return false;
		sum += a[i];
	}
	return cnt < m;
}
int main()
{
	cin >> n >> m;
	long long sum = 0;
	for(int i = 1; i <= n; i++){
		cin >> a[i];
		sum += a[i];
	}
	int l = 0, r = sum;
	while(l < r){
		int mid = (l + r) >> 1;
		if(check(mid)){
			r = mid;
//			cout << endl << mid ;
		}
		else l = mid + 1;
//		cout << endl;
	}
	cout << r;
}
